// Function to approve tokens
async function approveTokens(tokenContract, spenderAddress, amount) {
  try {
    const tx = await tokenContract.approve(spenderAddress, ethers.utils.parseUnits(amount));
    const receipt = await web3.eth.waitForTransactionReceipt(tx.hash);
    return true;
  } catch (error) {
    console.error(error);
    return false;
  }
}

// Function to swap tokens
async function swapTokens(tokenContract1, tokenContract2, amount1, amount2) {
  try {
    // Approve tokens for transfer
    await approveTokens(tokenContract1, ethTokenAddress, "1000000"); // Replace with actual ETH address and max uint256 value
    await approveTokens(tokenContract2, daiTokenAddress, "1000000"); // Replace with actual DAI address and max uint256 value

    // Get the swap function from the DEX contract
    const dexContract = new ethers.Contract(YOUR_DEX_ADDRESS, YOUR_DEX_ABI, web3.currentProvider); // Replace with actual DEX contract address and ABI
    const swapFunction = dexContract.swapTokens;

    // Execute the swap transaction
    const tx = await swapFunction(amount1, amount2);
    const receipt = await web3.eth.waitForTransactionReceipt(tx.hash);
    return true;
  } catch (error) {
    console.error(error);
    return false;
  }
}

